#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100005
#define MAX_Q 100005
// Define the structure for a tree node
typedef struct TreeNode {
    int value;
    int numNodes;
    struct TreeNode** children;
} TreeNode;
// Function to create a new tree node
TreeNode* createTreeNode(int value) {
    TreeNode* node = (TreeNode*)malloc(sizeof(TreeNode));
    node->value = value;
    node->numNodes = 1;
    node->children = NULL;
    return node;
}
// Function to add a child to a tree node
void addChild(TreeNode* parent, TreeNode* child) {
    parent->numNodes++;
    parent->children = (TreeNode**)realloc(parent->children, parent->numNodes * sizeof(TreeNode*));
    parent->children[parent->numNodes - 1] = child;
}
// Function to calculate the sum of values in a subtree
int calculateSum(TreeNode* node) {
    int sum = node->value;
    for (int i = 0; i < node->numNodes - 1; i++) {
        sum += calculateSum(node->children[i]);
    }
    return sum;
}
// Function to add a value to all nodes in a subtree
void addValue(TreeNode* node, int value) {
    node->value += value;
    for (int i = 0; i < node->numNodes - 1; i++) {
        addValue(node->children[i], value);
    }
}
// Function to swap two subtrees
void swapSubtrees(TreeNode* node1, TreeNode* node2) {
    // Swap the values and children of the two nodes
    int tempValue = node1->value;
    node1->value = node2->value;
    node2->value = tempValue;
    TreeNode** tempChildren = node1->children;
    node1->children = node2->children;
    node2->children = tempChildren;
}
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    // Create the tree nodes
    TreeNode** nodes = (TreeNode**)malloc(N * sizeof(TreeNode*));
    for (int i = 0; i < N; i++) {
        int value;
        scanf("%d", &value);
        nodes[i] = createTreeNode(value);
    }
    // Add edges to the tree
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--;
        v--;
        addChild(nodes[u], nodes[v]);
    }
    // Handle queries
    for (int i = 0; i < Q; i++) {
        int qtype;
        scanf("%d", &qtype);
        if (qtype == 1) {
            int u;
            scanf("%d", &u);
            u--;
            printf("%d\n", calculateSum(nodes[u]));
        } else if (qtype == 2) {
            int u, value;
            scanf("%d %d", &u, &value);
            u--;
            addValue(nodes[u], value);
        } else if (qtype == 3) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            // Check if the subtrees are disjoint
            if (nodes[u]->numNodes - 1 == 0 && nodes[v]->numNodes - 1 == 0) {
                swapSubtrees(nodes[u], nodes[v]);
            } else {
                printf("-1\n");
            }
        }
    }
    return 0;
}

