import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static class TreeNode {
        int value;
        List<TreeNode> children;
        public TreeNode(int value) {
            this.value = value;
            this.children = new ArrayList<>();
        }
    }
    // Function to calculate the sum of values in a subtree
    public static int calculateSum(TreeNode node) {
        int sum = node.value;
        for (TreeNode child : node.children) {
            sum += calculateSum(child);
        }
        return sum;
    }
    // Function to add a value to all nodes in a subtree
    public static void addValue(TreeNode node, int value) {
        node.value += value;
        for (TreeNode child : node.children) {
            addValue(child, value);
        }
    }
    // Function to swap two subtrees
    public static void swapSubtrees(TreeNode node1, TreeNode node2) {
        // Swap the values and children of the two nodes
        int tempValue = node1.value;
        node1.value = node2.value;
        node2.value = tempValue;
        List<TreeNode> tempChildren = node1.children;
        node1.children = node2.children;
        node2.children = tempChildren;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        // Create the tree nodes
        TreeNode[] nodes = new TreeNode[N];
        for (int i = 0; i < N; i++) {
            int value = scanner.nextInt();
            nodes[i] = new TreeNode(value);
        }
        // Add edges to the tree
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            nodes[u].children.add(nodes[v]);
        }
        // Handle queries
        for (int i = 0; i < Q; i++) {
            int qtype = scanner.nextInt();
            if (qtype == 1) {
                int u = scanner.nextInt() - 1;
                System.out.println(calculateSum(nodes[u]));
            } else if (qtype == 2) {
                int u = scanner.nextInt() - 1;
                int value = scanner.nextInt();
                addValue(nodes[u], value);
            } else if (qtype == 3) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                // Check if the subtrees are disjoint
                if (nodes[u].children.isEmpty() && nodes[v].children.isEmpty()) {
                    swapSubtrees(nodes[u], nodes[v]);
                } else {
                    System.out.println(-1);
                }
            }
        }
    }
}

